fix.codigo_loadLogs_reemplazar:
const { logs: auditStoreLogs, loadLogs: loadAuditStoreLogs } = useAuditStore();

const loadLogs = async () => {
  setLoading(true);
  try {
    // 1. Cargar logs del AuditStore (IndexedDB con hash chain)
    await loadAuditStoreLogs();

    // 2. Cargar logs del CMS store (localStorage/Neon)
    let neonLogs: any[] = [];
    if (window.electronAPI?.db?.getAuditLogs) {
      neonLogs = await window.electronAPI.db.getAuditLogs();
    }

    // 3. Unificar y deduplicar por id+timestamp
    const combinedMap = new Map<string, any>();
    [...auditStoreLogs, ...neonLogs].forEach(log => {
      const key = log.id || `${log.timestamp}_${log.accion}`;
      if (!combinedMap.has(key)) combinedMap.set(key, log);
    });

    const filtered = [...combinedMap.values()]
      .filter((l: any) => !SESSION_ACTIONS.has(l.accion))
      .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());

    setAuditLogs(filtered);
  } catch (err) {
    console.error('Error cargando audit logs:', err);
  } finally {
    setLoading(false);
  }
};

useEffect(() => { loadLogs(); }, []);

